import{_ as l,o as i,c as e,al as r}from"./chunks/framework.DPRzuwkw.js";const _=JSON.parse('{"title":"附属开发","description":"","frontmatter":{"next":{"text":"环境搭建","link":"/posts/docs/addon/01_environment"}},"headers":[],"relativePath":"posts/docs/addon/index.md","filePath":"posts/docs/addon/index.md","lastUpdated":1773840449000}'),t={name:"posts/docs/addon/index.md"};function n(o,a,s,h,d,c){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="附属开发" tabindex="-1">附属开发 <a class="header-anchor" href="#附属开发" aria-label="Permalink to “附属开发”">​</a></h1><p>欢迎来到 AnvilCraft 附属开发文档！本章节将指导您如何创建自己的 AnvilCraft 附属模组。</p><h2 id="什么是附属模组" tabindex="-1">什么是附属模组？ <a class="header-anchor" href="#什么是附属模组" aria-label="Permalink to “什么是附属模组？”">​</a></h2><p>附属模组是基于 AnvilCraft 核心模组构建的扩展模组，它允许开发者和创作者：</p><ul><li>添加新的物品和方块</li><li>创建自定义配方</li><li>扩展现有的 AnvilCraft 机制</li><li>与其他模组进行集成</li><li>为 AnvilCraft 生态系统贡献新内容</li></ul><h2 id="为什么创建附属模组" tabindex="-1">为什么创建附属模组？ <a class="header-anchor" href="#为什么创建附属模组" aria-label="Permalink to “为什么创建附属模组？”">​</a></h2><ol><li><strong>扩展功能</strong>：在不修改核心模组的情况下添加新内容</li><li><strong>保持兼容性</strong>：附属模组可以与 AnvilCraft 主模组及其他附属模组良好协作</li><li><strong>社区贡献</strong>：为 AnvilCraft 社区贡献您的创意和想法</li><li><strong>学习机会</strong>：通过实践深入了解 Minecraft 模组开发</li></ol><h2 id="开发前准备" tabindex="-1">开发前准备 <a class="header-anchor" href="#开发前准备" aria-label="Permalink to “开发前准备”">​</a></h2><p>在开始开发之前，您需要：</p><ol><li>熟悉 Java 编程语言</li><li>了解 Minecraft 原版机制</li><li>掌握基本的模组开发概念</li><li>准备好开发环境（JDK 21、IDE 等）</li></ol><h2 id="开发流程概览" tabindex="-1">开发流程概览 <a class="header-anchor" href="#开发流程概览" aria-label="Permalink to “开发流程概览”">​</a></h2><h3 id="基础开发" tabindex="-1">基础开发 <a class="header-anchor" href="#基础开发" aria-label="Permalink to “基础开发”">​</a></h3><ol><li><a href="./01_environment.html">环境搭建与模组构建</a> - 配置开发环境</li><li><a href="./02_create_item.html">创建你的第一个物品</a> - 学习基本的物品注册</li><li><a href="./03_create_block.html">创建你的第一个方块</a> - 学习基本的方块注册</li></ol><h3 id="进阶开发" tabindex="-1">进阶开发 <a class="header-anchor" href="#进阶开发" aria-label="Permalink to “进阶开发”">​</a></h3><ol start="4"><li><a href="./04_create_entity.html">注册实体</a> - 学习如何创建自定义实体</li><li><a href="./05_create_block_entity.html">方块实体开发</a> - 创建具有逻辑的方块</li><li><a href="./06_data_generation.html">数据生成器</a> - 自动生成游戏资源</li><li><a href="./07_config.html">配置系统</a> - 创建模组配置文件</li><li><a href="./08_recipe_integration.html">配方系统集成</a> - 集成 AnvilCraft 配方系统</li><li><a href="./09_event_system.html">事件系统</a> - 使用 NeoForge 事件系统</li><li><a href="./10_resources.html">资源和本地化</a> - 管理材质、模型和语言文件</li><li><a href="./11_networking.html">网络通信</a> - 实现客户端与服务端通信</li></ol><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to “技术栈”">​</a></h2><p>AnvilCraft 附属模组开发主要使用以下技术：</p><ul><li><strong>Java 21</strong> - 开发语言</li><li><strong>Gradle</strong> - 构建工具</li><li><strong>Registrum</strong> - 内容注册系统（AnvilLib 提供的注册 API，基于 Registrate 改进）</li><li><strong>NeoForge</strong> - 模组加载器 API</li><li><strong>Lombok</strong> - 简化 Java 代码编写</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h2><ul><li>遵循 AnvilCraft 的设计语言和风格</li><li>保持与原版 Minecraft 的一致性</li><li>充分利用 AnvilCraft 提供的 API</li><li>编写清晰的文档和注释</li><li>进行充分的测试</li></ul><p>准备好开始您的附属开发之旅了吗？让我们从<a href="./01_environment.html">环境搭建</a>开始吧！</p>',21)])])}const m=l(t,[["render",n]]);export{_ as __pageData,m as default};
